import json
import os
import logging
from datetime import datetime
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Configuration via environment variables
PROJECT_ID = os.environ.get("GCP_PROJECT_ID", os.environ.get("GCP_PROJECT", ""))
PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC", "file-processing-events")
FIRESTORE_COLLECTION = os.environ.get("FIRESTORE_COLLECTION", "processed_files")

# Initialize clients lazily to avoid cold start issues
_storage_client = None
_firestore_client = None
_pubsub_client = None


def _get_storage_client():
    global _storage_client
    if _storage_client is None:
        _storage_client = storage.Client()
    return _storage_client


def _get_firestore_client():
    global _firestore_client
    if _firestore_client is None:
        _firestore_client = firestore.Client()
    return _firestore_client


def _get_pubsub_client():
    global _pubsub_client
    if _pubsub_client is None:
        _pubsub_client = pubsub_v1.PublisherClient()
    return _pubsub_client


def process_file_from_gcs(bucket_name: str, file_name: str) -> dict:
    """
    Download and process a file from Cloud Storage.

    NOTE ON PERMISSIONS: This function requires the service account to have
    ONLY the following minimal permissions:
      - storage.objects.get (on the specific bucket) — NOT Storage Admin
      - datastore.entities.create / datastore.entities.update — via "Cloud Datastore User"
        scoped to the specific Firestore database
      - pubsub.topics.publish (on the specific topic) — NOT broad Pub/Sub Publisher

    SECURITY WARNING: Do NOT use roles/storage.admin for read-only file processing.
    Use roles/storage.objectViewer on the specific bucket instead.
    See deploy_secure.sh for the recommended least-privilege IAM setup.
    """
    client = _get_storage_client()
    bucket = client.bucket(bucket_name)
    blob = bucket.blob(file_name)

    if not blob.exists():
        raise FileNotFoundError(f"File {file_name} not found in bucket {bucket_name}")

    content = blob.download_as_bytes()
    metadata = {
        "bucket": bucket_name,
        "file_name": file_name,
        "size_bytes": blob.size,
        "content_type": blob.content_type,
        "md5_hash": blob.md5_hash,
        "created": blob.time_created.isoformat() if blob.time_created else None,
        "updated": blob.updated.isoformat() if blob.updated else None,
    }

    # Process based on content type
    processing_result = _process_content(content, blob.content_type, file_name)
    metadata["processing_result"] = processing_result

    return metadata


def _process_content(content: bytes, content_type: str, file_name: str) -> dict:
    """Process file content based on its type."""
    result = {
        "status": "processed",
        "processed_at": datetime.utcnow().isoformat(),
        "file_name": file_name,
    }

    if content_type and "json" in content_type:
        try:
            parsed = json.loads(content.decode("utf-8"))
            result["record_count"] = len(parsed) if isinstance(parsed, list) else 1
            result["format"] = "json"
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            result["status"] = "parse_error"
            result["error"] = str(e)

    elif content_type and "csv" in content_type:
        try:
            text = content.decode("utf-8")
            lines = text.strip().split("\n")
            result["record_count"] = max(0, len(lines) - 1)  # exclude header
            result["format"] = "csv"
        except UnicodeDecodeError as e:
            result["status"] = "parse_error"
            result["error"] = str(e)

    elif content_type and "text" in content_type:
        try:
            text = content.decode("utf-8")
            result["line_count"] = len(text.strip().split("\n"))
            result["char_count"] = len(text)
            result["format"] = "text"
        except UnicodeDecodeError as e:
            result["status"] = "parse_error"
            result["error"] = str(e)

    else:
        result["format"] = "binary"
        result["size_bytes"] = len(content)

    return result


def write_to_firestore(document_data: dict, document_id: str = None) -> str:
    """Write processing results to Firestore."""
    client = _get_firestore_client()
    collection_ref = client.collection(FIRESTORE_COLLECTION)

    document_data["written_to_firestore_at"] = datetime.utcnow().isoformat()

    if document_id:
        # Sanitize document ID for Firestore (no slashes allowed in doc IDs)
        safe_id = document_id.replace("/", "_").replace("\\", "_")
        doc_ref = collection_ref.document(safe_id)
        doc_ref.set(document_data, merge=True)
        return safe_id
    else:
        _timestamp, doc_ref = collection_ref.add(document_data)
        return doc_ref.id


def publish_to_pubsub(message_data: dict, attributes: dict = None) -> str:
    """Publish a message to Pub/Sub topic."""
    client = _get_pubsub_client()
    topic_path = client.topic_path(PROJECT_ID, PUBSUB_TOPIC)

    message_bytes = json.dumps(message_data, default=str).encode("utf-8")

    if attributes:
        # Pub/Sub attributes must be strings
        str_attributes = {k: str(v) for k, v in attributes.items() if v is not None}
        future = client.publish(topic_path, message_bytes, **str_attributes)
    else:
        future = client.publish(topic_path, message_bytes)

    message_id = future.result(timeout=30)
    logger.info(f"Published message {message_id} to {topic_path}")
    return message_id


def process_gcs_event(cloud_event):
    """
    Cloud Function entry point triggered by Cloud Storage events.

    Triggered by: google.cloud.storage.object.v1.finalized

    Deploy with:
        See deploy_secure.sh for secure deployment with least-privilege permissions.
    """
    data = cloud_event.data
    bucket_name = data["bucket"]
    file_name = data["name"]

    logger.info(f"Processing file: gs://{bucket_name}/{file_name}")

    response = {
        "bucket": bucket_name,
        "file": file_name,
        "status": "started",
        "timestamp": datetime.utcnow().isoformat(),
    }

    try:
        # Step 1: Process file from Cloud Storage
        file_metadata = process_file_from_gcs(bucket_name, file_name)
        response["file_metadata"] = file_metadata
        logger.info(f"File processed successfully: {file_name}")

        # Step 2: Write results to Firestore
        document_id = f"{bucket_name}_{file_name}"
        firestore_doc_id = write_to_firestore(
            document_data={
                "source_bucket": bucket_name,
                "source_file": file_name,
                "metadata": file_metadata,
                "processing_status": file_metadata.get("processing_result", {}).get(
                    "status", "unknown"
                ),
                "event_id": cloud_event.get("id", "unknown"),
            },
            document_id=document_id,
        )
        response["firestore_document_id"] = firestore_doc_id
        logger.info(f"Written to Firestore: {firestore_doc_id}")

        # Step 3: Publish event to Pub/Sub
        pubsub_message = {
            "event_type": "file_processed",
            "bucket": bucket_name,
            "file": file_name,
            "firestore_document_id": firestore_doc_id,
            "processing_result": file_metadata.get("processing_result", {}),
            "timestamp": datetime.utcnow().isoformat(),
        }
        message_id = publish_to_pubsub(
            message_data=pubsub_message,
            attributes={
                "bucket": bucket_name,
                "event_type": "file_processed",
                "content_type": file_metadata.get("content_type", "unknown"),
            },
        )
        response["pubsub_message_id"] = message_id
        logger.info(f"Published to Pub/Sub: {message_id}")

        response["status"] = "completed"

    except FileNotFoundError as e:
        logger.error(f"File not found: {e}")
        response["status"] = "error"
        response["error"] = str(e)
        _write_error_to_firestore(bucket_name, file_name, str(e))

    except Exception as e:
        logger.error(f"Error processing file {file_name}: {e}", exc_info=True)
        response["status"] = "error"
        response["error"] = str(e)
        _write_error_to_firestore(bucket_name, file_name, str(e))
        raise  # Re-raise so Cloud Functions marks this as failed for retry

    return response


def process_http_request(request):
    """
    HTTP-triggered Cloud Function entry point for manual/testing invocations.

    Expected JSON body:
    {
        "bucket": "my-bucket",
        "file": "path/to/file.json"
    }
    """
    try:
        request_json = request.get_json(silent=True)

        if not request_json:
            return json.dumps({"error": "Request body must be JSON"}), 400

        bucket_name = request_json.get("bucket")
        file_name = request_json.get("file")

        if not bucket_name or not file_name:
            return (
                json.dumps(
                    {"error": "Both 'bucket' and 'file' fields are required"}
                ),
                400,
            )

        logger.info(f"HTTP trigger: Processing gs://{bucket_name}/{file_name}")

        # Step 1: Process file
        file_metadata = process_file_from_gcs(bucket_name, file_name)

        # Step 2: Write to Firestore
        document_id = f"{bucket_name}_{file_name}"
        firestore_doc_id = write_to_firestore(
            document_data={
                "source_bucket": bucket_name,
                "source_file": file_name,
                "metadata": file_metadata,
                "processing_status": file_metadata.get("processing_result", {}).get(
                    "status", "unknown"
                ),
                "trigger": "http",
            },
            document_id=document_id,
        )

        # Step 3: Publish to Pub/Sub
        pubsub_message = {
            "event_type": "file_processed",
            "trigger": "http",
            "bucket": bucket_name,
            "file": file_name,
            "firestore_document_id": firestore_doc_id,
            "processing_result": file_metadata.get("processing_result", {}),
            "timestamp": datetime.utcnow().isoformat(),
        }
        message_id = publish_to_pubsub(
            message_data=pubsub_message,
            attributes={
                "bucket": bucket_name,
                "event_type": "file_processed",
                "trigger": "http",
            },
        )

        result = {
            "status": "completed",
            "file_metadata": file_metadata,
            "firestore_document_id": firestore_doc_id,
            "pubsub_message_id": message_id,
        }
        return json.dumps(result, default=str), 200

    except FileNotFoundError as e:
        return json.dumps({"error": str(e)}), 404
    except Exception as e:
        logger.error(f"HTTP processing error: {e}", exc_info=True)
        return json.dumps({"error": str(e)}), 500


def _write_error_to_firestore(bucket_name: str, file_name: str, error_msg: str):
    """Attempt to log errors to Firestore for observability."""
    try:
        write_to_firestore(
            document_data={
                "source_bucket": bucket_name,
                "source_file": file_name,
                "processing_status": "error",
                "error_message": error_msg,
                "error_at": datetime.utcnow().isoformat(),
            },
            document_id=f"error_{bucket_name}_{file_name}",
        )
    except Exception as e:
        logger.error(f"Failed to write error to Firestore: {e}")


